  const result = nextGeneration([
    [0, 0], [1, 0], [2, 0],
    [0, 1], [1, 1], [2, 1],
    [0, 2], [1, 2], [2, 2],
  ]);
  expect(sortCells(result)).toEqual(
    sortCells([
      [0, 0], [2, 0], [0, 2], [2, 2],
      [1, -1], [-1, 1], [3, 1], [1, 3],
    ]),
  );
});

